import e from"node:process";import o from"node:process";import t from"process";it("node:process should be the same as process",()=>{expect(o).toStrictEqual(t)});var{env:s,cwd:a,argv0:r,argv:c,platform:p,arch:l,hrtime:h,release:i,version:v,versions:u,exit:d}=o;it("should have a process env",()=>{expect(s).toEqual(e.env)});it("should have a process cwd",()=>{expect(a()).toEqual(e.cwd())});it("should have a process argv0",()=>{expect(r).toEqual(e.argv0)});it("should have a process argv",()=>{expect(c).toEqual(e.argv)});it("should have a process platform",()=>{expect(p).toEqual(e.platform)});it("should have a process arch",()=>{expect(l).toEqual(e.arch)});it("should have a process hrtime",()=>{expect(h.bigint()>0).toBeTruthy()});it("should have a process release",()=>{expect(i).toEqual(e.release)});it("should have a process version",()=>{expect(v).toEqual(e.version)});it("should have a process versions",()=>{expect(u).toEqual(e.versions)});it("should have a process exit",()=>{expect(d).toEqual(e.exit)});
